// Debug: check if soldiers exist, their state, and if enemies are nearby
var soldiers = UnityEngine.Object.FindObjectsOfType<TowerDefense.Tower.Soldier>();
UnityEngine.Debug.Log($"=== SOLDIER DEBUG === Found {soldiers.Length} soldiers");
foreach (var s in soldiers)
{
    UnityEngine.Debug.Log($"Soldier '{s.gameObject.name}' at {s.transform.position} | IsAlive={s.IsAlive} | State={s.State} | IsBlocking={s.IsBlocking} | Target={s.CurrentTarget?.name ?? "null"}");
}

var enemies = UnityEngine.Object.FindObjectsOfType<TowerDefense.Enemy.Enemy>();
UnityEngine.Debug.Log($"Found {enemies.Length} enemies");
foreach (var e in enemies)
{
    if (!e.IsDead)
        UnityEngine.Debug.Log($"Enemy '{e.gameObject.name}' at {e.transform.position} | IsDead={e.IsDead}");
}

var barracks = UnityEngine.Object.FindObjectsOfType<TowerDefense.Tower.BarracksAttack>();
UnityEngine.Debug.Log($"Found {barracks.Length} barracks");
foreach (var b in barracks)
{
    UnityEngine.Debug.Log($"Barracks '{b.gameObject.name}' at {b.transform.position} | SoldiersSpawned={b.Soldiers.Count} | AliveCount={b.AliveSoldierCount} | RallyPoint={b.RallyPoint?.position.ToString() ?? "null"}");
}

var spawner = UnityEngine.Object.FindObjectOfType<TowerDefense.Enemy.EnemySpawner>();
if (spawner != null)
    UnityEngine.Debug.Log($"EnemySpawner found at {spawner.transform.position}");
else
    UnityEngine.Debug.Log("NO EnemySpawner found!");

var soldiers = UnityEngine.Object.FindObjectsOfType<TowerDefense.Tower.Soldier>();
foreach (var s in soldiers)
{
    var homePoint = s.transform.parent?.GetComponent<TowerDefense.Tower.BarracksAttack>()?.RallyPoint;
    if (homePoint != null)
    {
        float dist = UnityEngine.Vector3.Distance(s.transform.position, homePoint.position);
        UnityEngine.Debug.Log($"Soldier at {s.transform.position}, RallyPoint at {homePoint.position}, dist={dist:F3}, returning threshold=0.3");
    }
    else
    {
        UnityEngine.Debug.Log($"Soldier at {s.transform.position}, NO rally point found!");
    }

    // Check _data values
    var data = s.GetComponent<TowerDefense.Tower.Soldier>();
    var dataField = data.GetType().GetField("_data", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
    var soldierData = dataField?.GetValue(data) as TowerDefense.Data.SoldierData;
    if (soldierData != null)
    {
        UnityEngine.Debug.Log($"  engageRange={soldierData.engageRange}, moveSpeed={soldierData.moveSpeed}, attackRange={soldierData.attackRange}");
    }
}

