var soldiers = UnityEngine.Object.FindObjectsOfType<TowerDefense.Tower.Soldier>();
foreach (var s in soldiers)
{
    // Check if the soldier's Update is even running
    var go = s.gameObject;
    UnityEngine.Debug.Log($"Soldier '{go.name}' activeInHierarchy={go.activeInHierarchy} | activeSelf={go.activeSelf}");

    // Check the Soldier component enabled
    UnityEngine.Debug.Log($"  Soldier.enabled={s.enabled}");

    // Direct test: set transform position directly
    var oldPos = s.transform.position;
    s.transform.position = new UnityEngine.Vector3(12f, 5f, 0f);
    UnityEngine.Debug.Log($"  Direct set: old={oldPos}, new={s.transform.position}");

    // Wait - check if rb overrides it
    var rb = s.GetComponent<UnityEngine.Rigidbody2D>();
    if (rb != null) UnityEngine.Debug.Log($"  RB position={rb.position}");
}

